package dao.impl; import dao.PlayerCardDao;import model.PlayerCard;import util.DBUtil;import exception.AppException;import java.sql.*;import java.util.*;
public class PlayerCardDaoImpl implements PlayerCardDao{
 public List<PlayerCard> findAll(){return search("");}
 public List<PlayerCard> search(String k){List<PlayerCard> list=new ArrayList<>();String sql="SELECT * FROM player_cards WHERE card_name LIKE ? OR player_name LIKE ? OR sport LIKE ? ORDER BY id";try(Connection c=DBUtil.getConnection();PreparedStatement ps=c.prepareStatement(sql)){String q="%"+k+"%";ps.setString(1,q);ps.setString(2,q);ps.setString(3,q);ResultSet r=ps.executeQuery();while(r.next())list.add(map(r));return list;}catch(Exception e){throw new AppException("查詢球員卡失敗",e);}}
 public void add(PlayerCard x){String sql="INSERT INTO player_cards(card_name,player_name,sport,team,card_year,brand,card_number,grade,price,quantity,description,image_path) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)";exec(sql,x,false);} public void update(PlayerCard x){String sql="UPDATE player_cards SET card_name=?,player_name=?,sport=?,team=?,card_year=?,brand=?,card_number=?,grade=?,price=?,quantity=?,description=?,image_path=? WHERE id=?";exec(sql,x,true);} private void exec(String sql,PlayerCard x,boolean up){try(Connection c=DBUtil.getConnection();PreparedStatement ps=c.prepareStatement(sql)){ps.setString(1,x.cardName);ps.setString(2,x.playerName);ps.setString(3,x.sport);ps.setString(4,x.team);ps.setInt(5,x.cardYear);ps.setString(6,x.brand);ps.setString(7,x.cardNumber);ps.setString(8,x.grade);ps.setDouble(9,x.price);ps.setInt(10,x.quantity);ps.setString(11,x.description);ps.setString(12,x.imagePath);if(up)ps.setInt(13,x.id);ps.executeUpdate();}catch(Exception e){throw new AppException("儲存球員卡失敗",e);}}
 public void delete(int id){try(Connection c=DBUtil.getConnection();PreparedStatement ps=c.prepareStatement("DELETE FROM player_cards WHERE id=?")){ps.setInt(1,id);ps.executeUpdate();}catch(Exception e){throw new AppException("刪除球員卡失敗",e);}}
 private PlayerCard map(ResultSet r)throws Exception{PlayerCard x=new PlayerCard();x.id=r.getInt("id");x.cardName=r.getString("card_name");x.playerName=r.getString("player_name");x.sport=r.getString("sport");x.team=r.getString("team");x.cardYear=r.getInt("card_year");x.brand=r.getString("brand");x.cardNumber=r.getString("card_number");x.grade=r.getString("grade");x.price=r.getDouble("price");x.quantity=r.getInt("quantity");x.description=r.getString("description");x.imagePath=r.getString("image_path");return x;}
}
